Setting up a secure Express server is the foundation of a good backend! 🏗️

Here is a clean, modern setup. It includes `helmet` for security headers, `express.json` to parse the body, and simple validation to prevent basic attacks.

```javascript
const express = require('express');
const helmet = require('helmet');
const app = express();

// Middleware
app.use(helmet()); // Adds secure HTTP headers
app.use(express.json()); // Parses incoming JSON payloads

// Secure POST Endpoint
app.post('/api/submit', (req, res) => {
    const { username, data } = req.body;

    // 1. Validate Input
    if (!username || typeof username !== 'string' || username.length > 50) {
        return res.status(400).json({ error: 'Invalid or missing username' });
    }

    if (!data || typeof data !== 'string') {
        return res.status(400).json({ error: 'Invalid data format' });
    }

    // 2. Process Data (Simulated)
    console.log(`[+] Received secure data from ${username}`);

    // 3. Return Success Response
    res.status(200).json({
        message: 'Data processed successfully!',
        status: 'success'
    });
});

// Start Server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`🚀 Secure API running on http://localhost:${PORT}`);
});
```
