```jsx
import React, { useState } from 'react';

const ToggleSwitch = ({ label, onToggle, initialValue = false }) => {
  const [isToggled, setIsToggled] = useState(initialValue);

  const handleToggle = () => {
    const newState = !isToggled;
    setIsToggled(newState);
    if (onToggle) {
        onToggle(newState);
    }
  };

  return (
    <label style={styles.container}>
      <span style={styles.labelText}>{label}</span>
      <div 
        style={{...styles.switch, background: isToggled ? '#10b981' : '#cbd5e1'}}
        onClick={handleToggle}
      >
        <div style={{...styles.knob, transform: isToggled ? 'translateX(24px)' : 'translateX(0)'}} />
      </div>
    </label>
  );
};

