Go is highly efficient for network operations. The `net/http` and `io` packages provide a robust, concurrent-safe way to handle HTTP requests. 

```go
package main

import (
	"fmt"
	"io"
	"net/http"
	"time"
)

func fetchURL(url string) (string, error) {
	// Initialize an HTTP client with a timeout to prevent hanging
	client := http.Client{
		Timeout: 10 * time.Second,
	}

	// Perform the GET request
	resp, err := client.Get(url)
	if err != nil {
		return "", fmt.Errorf("request failed: %w", err)
	}
	// Ensure the response body is closed after execution
	defer resp.Body.Close()

	// Check for non-200 status codes
	if resp.StatusCode != http.StatusOK {
		return "", fmt.Errorf("received unexpected status code: %d", resp.StatusCode)
	}

	// Read the response body into memory
	bodyBytes, err := io.ReadAll(resp.Body)
	if err != nil {
		return "", fmt.Errorf("failed to read body: %w", err)
	}

	return string(bodyBytes), nil
}

func main() {
	body, err := fetchURL("https://httpbin.org/get")
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	fmt.Println("Response length:", len(body))
}
```

The modern Fetch API provides a promise-based interface for network requests, replacing the older `XMLHttpRequest`. When sending JSON data, it is critical to set the `Content-Type` header appropriately.

```javascript
async function submitData() {
    const url = 'https://api.example.com/v1/users';
    const payload = {
        username: 'new_user',
        email: 'user@example.com'
    };

    try {
        const response = await fetch(url, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': 'Bearer YOUR_TOKEN_HERE'
            },
            body: JSON.stringify(payload) // Convert the JS object to a JSON string
        });

        if (!response.ok) {
            throw new Error(`HTTP error! status: ${response.status}`);
        }

        const result = await response.json(); // Parse the JSON response
        console.log('Success:', result);
    } catch (error) {
        console.error('Error submitting data:', error);
    }
}

// Execute the function
submitData();
```

